import asyncio
import os
from dotenv import load_dotenv

load_dotenv()
from routers.query import query_endpoint
from models.schemas import QueryRequest, UserContext

async def test():
    req = QueryRequest(audio_base64="", user_context=UserContext())
    res = await query_endpoint(req)
    print("Res text:", res.answer_text_kn)
    print("Res has audio:", bool(res.audio_base64))
    print("Res error:", getattr(res, "error", None))

asyncio.run(test())
